python3 -c "
import json

with open('/workspace/notes.json') as f:
    notes = json.load(f)

duration = 5.8  # from earlier check
errors = []

for i, n in enumerate(notes):
    # Check keys
    expected_keys = {'onset_sec', 'offset_sec', 'pitch_midi', 'velocity'}
    if set(n.keys()) != expected_keys:
        errors.append(f'Note {i}: keys mismatch: {set(n.keys())}')
    # Check types
    if not isinstance(n['onset_sec'], (int, float)):
        errors.append(f'Note {i}: onset_sec not float')
    if not isinstance(n['offset_sec'], (int, float)):
        errors.append(f'Note {i}: offset_sec not float')
    if not isinstance(n['pitch_midi'], int):
        errors.append(f'Note {i}: pitch_midi not int: {type(n[\"pitch_midi\"])}')
    if not isinstance(n['velocity'], int):
        errors.append(f'Note {i}: velocity not int: {type(n[\"velocity\"])}')
    # Check values
    if not (0 <= n['pitch_midi'] <= 127):
        errors.append(f'Note {i}: pitch_midi out of range: {n[\"pitch_midi\"]}')
    if not (1 <= n['velocity'] <= 127):
        errors.append(f'Note {i}: velocity out of range: {n[\"velocity\"]}')
    if n['offset_sec'] <= n['onset_sec']:
        errors.append(f'Note {i}: offset_sec <= onset_sec')
    if n['offset_sec'] > duration + 0.1:
        errors.append(f'Note {i}: offset_sec exceeds duration+0.1: {n[\"offset_sec\"]}')
    # Check sorted
    if i > 0 and n['onset_sec'] <= notes[i-1]['onset_sec']:
        errors.append(f'Note {i}: onset_sec not strictly ascending')

if errors:
    for e in errors:
        print(e)
else:
    print('All validation checks passed!')
    print(f'Total notes: {len(notes)}')
"
